from llama_stack_client import Tool
from typing import Dict, List

@pydantic.dataclass
class RetrievalInput:
    query: str
    source_type: str = 'vector'

@pydantic.dataclass
class RetrievalOutput:
    chunks: List[Dict[str, str]]
    source_ids: List[str]
    relevance_scores: List[float]

retrieval_tool = Tool(
    name='multi_source_retrieve',
    description='Retrieve from Pinecone, Weaviate, or web sources',
    input_schema=RetrievalInput,
    output_schema=RetrievalOutput,
    func=lambda input: pinecone_retrieve(input.query) + web_search(input.query)
)

rag_agent.add_tool(retrieval_tool)

