@vex.assertion('source_faithfulness')
def check_source_faithfulness(response: str, sources: List[Dict]) -> bool:
    for citation in extract_citations(response):
        source_content = get_source_by_id(sources, citation.source_id)
        if semantic_similarity(response, source_content) < 0.85:
            return False
    return True

# Integrated in Vex workflow
vex.verify(raw_response, custom_assertions=[check_source_faithfulness])
